import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  // Step 1: ONE broad Polymarket discovery + Kalshi crossref in parallel (different toolNames)
  const discovery = await callMcpSkillsParallel({
    label: "iran-crossvenue-discovery",
    calls: [
      {
        key: "poly-broad",
        toolId,
        toolName: "search_markets",
        args: { query: "Iran US military invasion ground troops boots war strike attack 2025 2026", limit: 50, status: "all" },
      },
      {
        key: "kalshi-iran",
        toolId,
        toolName: "polymarket_crossref_kalshi",
        args: { keywords: "Iran US military invasion ground troops war 2025 2026", limit: 10 },
      },
    ],
  });

  // Extract Polymarket search results
  var polyRaw = [];
  var polyEntry = discovery.results.find(function (e) { return e.key === "poly-broad"; });
  if (polyEntry && polyEntry.status === "fulfilled" && Array.isArray(polyEntry.value?.results)) {
    polyRaw = polyEntry.value.results;
  }

  // Extract Kalshi crossref results
  var kalshiRaw = [];
  var kalshiEntry = discovery.results.find(function (e) { return e.key === "kalshi-iran"; });
  if (kalshiEntry && kalshiEntry.status === "fulfilled" && Array.isArray(kalshiEntry.value?.kalshiResults)) {
    kalshiRaw = kalshiEntry.value.kalshiResults;
  }

  // Step 2: If Polymarket pool is thin, one sequential follow-up search (same endpoint)
  if (polyRaw.length < 8) {
    try {
      var followUp = await callMcpSkill({
        toolId,
        toolName: "search_markets",
        args: { query: "Iran allied forces Israel ground war troops escalation conflict", limit: 20, status: "all" },
      });
      if (Array.isArray(followUp?.results)) {
        var seen = new Set(polyRaw.map(function (m) { return m.conditionId || m.title; }));
        for (var fm of followUp.results) {
          var fk = fm.conditionId || fm.title;
          if (!seen.has(fk)) { seen.add(fk); polyRaw.push(fm); }
        }
      }
    } catch (e) { /* bounded fallback: proceed with what we have */ }
  }

  // Step 3: Deterministic semantic targeting on merged Polymarket candidates
  var ranked = pickTopSemanticCandidates({
    target: "US or allied boots on the ground in Iran — ground invasion, troop deployment, or ground war involving Iran directly",
    candidates: polyRaw,
    requiredTerms: ["iran", "ground", "boots", "invasion", "troops", "military", "war", "allied", "forces", "strike", "attack"],
    avoidTerms: ["iraq", "syria", "lebanon", "yemen", "gaza", "ukraine", "russia", "china", "north korea", "tariff", "crypto", "bitcoin", "sanctions only", "diplomatic", "nuclear deal"],
    limit: 10,
  });

  // Also semantically rank Kalshi results for the same scenario
  var kalshiRanked = [];
  if (kalshiRaw.length > 0) {
    kalshiRanked = pickTopSemanticCandidates({
      target: "US or allied boots on the ground in Iran — ground invasion, troop deployment, or ground war",
      candidates: kalshiRaw.map(function (k) { return { ...k, title: k.title }; }),
      requiredTerms: ["iran", "ground", "invasion", "troops", "military", "war", "strike", "attack", "boots"],
      avoidTerms: ["iraq", "syria", "lebanon", "yemen", "ukraine", "russia", "tariff", "crypto"],
      limit: 5,
    });
  }

  // Step 4: Sequentially check efficiency on top live Polymarket markets (same endpoint)
  var liveMarkets = ranked.filter(function (m) { return m.status === "live"; });
  var efficiencyResults = [];

  for (var i = 0; i < Math.min(liveMarkets.length, 5); i++) {
    var market = liveMarkets[i];
    try {
      var eff = await callMcpSkill({
        toolId,
        toolName: "check_market_efficiency",
        args: { slug: market.slug || undefined, conditionId: market.conditionId || undefined },
      });
      efficiencyResults.push(eff);
    } catch (e) {
      efficiencyResults.push({ error: e.message, market: market.title });
    }
  }

  // Step 5: Sequential risk-off proxy searches on Polymarket (same endpoint)
  var riskOffMarkets = [];
